"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[93320],{79337:e=>{e.exports=JSON.parse('{"tag":{"label":"procedural","permalink":"/dst-api-webdocs/docs/tags/procedural","allTagsPath":"/dst-api-webdocs/docs/tags","count":18,"items":[{"id":"game-scripts/map/rooms/forest/DLCrooms","title":"Dlcrooms","description":"Registers forest biome-specific room templates with unique entity distribution and static layouts for procedural world generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/DLCrooms"},{"id":"game-scripts/map/forest_map","title":"Forest Map","description":"Handles procedural generation of the Forest biome\'s terrain, topology, entities, roads, and seasonal/weather configuration for Don\'t Starve Together world generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/forest_map"},{"id":"game-scripts/map/rooms/cave/generic","title":"Generic","description":"Defines static cave room templates including impassable pit rooms and cave exit rooms with distributed flora and light assets.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/cave/generic"},{"id":"game-scripts/map/rooms/forest/giants","title":"Giants","description":"Registers the MooseGooseBreedingGrounds room configuration for forest world generation, defining its visual style, tags, and biome content rules.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/giants"},{"id":"game-scripts/map/monkeyisland_worldgen","title":"Monkeyisland Worldgen","description":"Generates dock systems and associated assets for monkey islands during world generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/monkeyisland_worldgen"},{"id":"game-scripts/map/network","title":"Network","description":"Manages world map graph structure including nodes, edges, and child subgraphs for procedural level generation and rendering in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/map/network"},{"id":"game-scripts/map/object_layout","title":"Object Layout","description":"Provides layout definition, conversion, and placement utilities for world generation, supporting static and procedural positioning of prefabs in maps.","permalink":"/dst-api-webdocs/docs/game-scripts/map/object_layout"},{"id":"game-scripts/map/rooms/forest/pigs","title":"Pigs","description":"Defines forest biome room templates for pig settlements, including pig houses, shrines, and villages, with randomized contents and conditional decor based on special events.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/pigs"},{"id":"game-scripts/map/placement","title":"Placement","description":"Provides procedural positioning utilities for map nodes using various spatial distribution algorithms (random line, circular offset, circular edge) and two placement strategies (mode0, random).","permalink":"/dst-api-webdocs/docs/game-scripts/map/placement"},{"id":"game-scripts/map/rooms/cave/ruins","title":"Ruins","description":"Defines procedural cave room templates for the Ruins biome, including layouts and distribution rules for flora, structures, and spawners.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/cave/ruins"},{"id":"game-scripts/map/rooms/forest/spider","title":"Spider","description":"Defines three procedural room templates (SpiderCity, SpiderVillage, SpiderVillageSwamp) for generating spider-infested areas in the Forest, Rocky, and Marsh biomes.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/spider"},{"id":"game-scripts/map/rooms/cave/swamp","title":"Swamp","description":"Defines cave swamp map room templates with varying layouts, densities, and prefab distributions for procedural world generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/cave/swamp"},{"id":"game-scripts/map/rooms/forest/tallbird","title":"Tallbird","description":"Defines a room template named TallbirdNests used in the forest level to procedurally generate nest clusters containing tallbird nests, rocks, and other sparse environmental objects.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/tallbird"},{"id":"game-scripts/map/task","title":"Task","description":"Represents a procedural map generation task with room placement rules, locking/Key requirements, and special room configurations.","permalink":"/dst-api-webdocs/docs/game-scripts/map/task"},{"id":"game-scripts/map/rooms/forest/terrain_forest","title":"Terrain Forest","description":"Registers multiple forest-themed world room templates with specific tile values, spawn weights, and static layout counts for procedural map generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/terrain_forest"},{"id":"game-scripts/map/rooms/forest/terrain_grass","title":"Terrain Grass","description":"Defines several forest-themed terrain room templates for procedural world generation, specifying tile type, visual tint, spawn tags, and content distribution rules for flora and objects.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/terrain_grass"},{"id":"game-scripts/map/rooms/forest/terrain_marsh","title":"Terrain Marsh","description":"Registers marsh-themed room templates for procedural map generation with specific prefabs, distribution rules, and visual properties.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/terrain_marsh"},{"id":"game-scripts/map/rooms/forest/terrain_noise","title":"Terrain Noise","description":"Adds a room template for procedural ground noise assets in forest and cave biomes, including flora, rocks, and spawn markers with weighted distribution rules.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/terrain_noise"}],"unlisted":false}}')}}]);